namespace ContosoUniversity.Tests;

[TestClass]
public sealed class PaginatedListTests
{
    [TestMethod]
    public void Constructor_WithItems_SetsPageIndexAndTotalPages()
    {
        // Arrange
        var items = new List<string> { "a", "b", "c" };

        // Act
        var sut = new PaginatedList<string>(items, count: 10, pageIndex: 2, pageSize: 3);

        // Assert
        Assert.AreEqual(2, sut.PageIndex);
        Assert.AreEqual(4, sut.TotalPages); // ceil(10/3) = 4
        Assert.AreEqual(3, sut.Count);
    }

    [TestMethod]
    [DataRow(10, 5, 2, DisplayName = "10 items, page size 5 = 2 pages")]
    [DataRow(11, 5, 3, DisplayName = "11 items, page size 5 = 3 pages")]
    [DataRow(1, 10, 1, DisplayName = "1 item, page size 10 = 1 page")]
    [DataRow(0, 10, 0, DisplayName = "0 items, page size 10 = 0 pages")]
    [DataRow(10, 1, 10, DisplayName = "10 items, page size 1 = 10 pages")]
    public void Constructor_VariousCounts_CalculatesTotalPagesCorrectly(int count, int pageSize, int expectedTotalPages)
    {
        // Act
        var sut = new PaginatedList<int>(new List<int>(), count, pageIndex: 1, pageSize);

        // Assert
        Assert.AreEqual(expectedTotalPages, sut.TotalPages);
    }

    [TestMethod]
    public void HasPreviousPage_OnFirstPage_ReturnsFalse()
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), count: 10, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsFalse(sut.HasPreviousPage);
    }

    [TestMethod]
    public void HasPreviousPage_OnSecondPage_ReturnsTrue()
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), count: 10, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.IsTrue(sut.HasPreviousPage);
    }

    [TestMethod]
    public void HasNextPage_OnLastPage_ReturnsFalse()
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), count: 10, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.IsFalse(sut.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_BeforeLastPage_ReturnsTrue()
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), count: 10, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsTrue(sut.HasNextPage);
    }

    [TestMethod]
    public void HasNextPage_ZeroItems_ReturnsFalse()
    {
        // Arrange
        var sut = new PaginatedList<int>(new List<int>(), count: 0, pageIndex: 1, pageSize: 5);

        // Assert
        Assert.IsFalse(sut.HasNextPage);
    }

    [TestMethod]
    public void Constructor_AddsItemsToList()
    {
        // Arrange
        var items = new List<string> { "alpha", "beta", "gamma" };

        // Act
        var sut = new PaginatedList<string>(items, count: 3, pageIndex: 1, pageSize: 10);

        // Assert
        CollectionAssert.AreEqual(items, sut);
    }

    [TestMethod]
    public void Create_ReturnsCorrectPage()
    {
        // Arrange
        var source = Enumerable.Range(1, 20).AsQueryable();

        // Act
        var sut = PaginatedList<int>.Create(source, pageIndex: 2, pageSize: 5);

        // Assert
        Assert.AreEqual(2, sut.PageIndex);
        Assert.AreEqual(4, sut.TotalPages);
        Assert.AreEqual(5, sut.Count);
        Assert.AreEqual(6, sut[0]); // skip 5, take 5 -> 6,7,8,9,10
        Assert.AreEqual(10, sut[4]);
    }

    [TestMethod]
    public void Create_FirstPage_ReturnsFirstItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var sut = PaginatedList<int>.Create(source, pageIndex: 1, pageSize: 3);

        // Assert
        Assert.AreEqual(1, sut.PageIndex);
        Assert.AreEqual(3, sut.TotalPages); // ceil(7/3) = 3
        Assert.AreEqual(3, sut.Count);
        Assert.AreEqual(1, sut[0]);
        Assert.AreEqual(3, sut[2]);
    }

    [TestMethod]
    public void Create_LastPartialPage_ReturnsRemainingItems()
    {
        // Arrange
        var source = Enumerable.Range(1, 7).AsQueryable();

        // Act
        var sut = PaginatedList<int>.Create(source, pageIndex: 3, pageSize: 3);

        // Assert
        Assert.AreEqual(1, sut.Count); // only 1 item on last page (7 total, pages of 3)
        Assert.AreEqual(7, sut[0]);
    }
}

