using ContosoUniversity.Models;
using ContosoUniversity.Services;

namespace ContosoUniversity.Tests.Services;

[TestClass]
public sealed class NotificationServiceTests
{
    /// <summary>
    /// Drain the static queue before each test to prevent cross-test pollution.
    /// </summary>
    [TestInitialize]
    public void DrainQueue()
    {
        using var svc = new NotificationService();
        while (svc.ReceiveNotification() != null) { }
    }

    [TestMethod]
    public void SendNotification_WithDisplayName_EnqueuesNotification()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Student", "42", "John Doe", EntityOperation.CREATE, "Admin");

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Student", notification.EntityType);
        Assert.AreEqual("42", notification.EntityId);
        Assert.AreEqual("CREATE", notification.Operation);
        Assert.AreEqual("Admin", notification.CreatedBy);
        Assert.IsFalse(notification.IsRead);
        Assert.IsNull(notification.ReadAt);
        Assert.IsTrue(notification.Message.Contains("Student 'John Doe'"));
    }

    [TestMethod]
    public void SendNotification_WithoutDisplayName_UsesIdInMessage()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Course", "1050", EntityOperation.UPDATE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Course (ID: 1050)"));
        Assert.IsTrue(notification.Message.Contains("updated"));
    }

    [TestMethod]
    public void SendNotification_WithoutUserName_DefaultsToSystem()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Department", "1", EntityOperation.CREATE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("System", notification.CreatedBy);
    }

    [TestMethod]
    [DataRow(EntityOperation.CREATE, "has been created")]
    [DataRow(EntityOperation.UPDATE, "has been updated")]
    [DataRow(EntityOperation.DELETE, "has been deleted")]
    public void SendNotification_AllOperations_GeneratesCorrectMessage(EntityOperation operation, string expectedFragment)
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Entity", "1", "TestEntity", operation);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains(expectedFragment),
            $"Expected message to contain '{expectedFragment}', but was '{notification.Message}'");
    }

    [TestMethod]
    public void ReceiveNotification_EmptyQueue_ReturnsNull()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        var result = sut.ReceiveNotification();

        // Assert
        Assert.IsNull(result);
    }

    [TestMethod]
    public void ReceiveNotification_MultipleMessages_ReturnsFIFO()
    {
        // Arrange
        using var sut = new NotificationService();
        sut.SendNotification("A", "1", "First", EntityOperation.CREATE);
        sut.SendNotification("B", "2", "Second", EntityOperation.UPDATE);
        sut.SendNotification("C", "3", "Third", EntityOperation.DELETE);

        // Act & Assert
        var first = sut.ReceiveNotification();
        Assert.IsNotNull(first);
        Assert.AreEqual("A", first.EntityType);

        var second = sut.ReceiveNotification();
        Assert.IsNotNull(second);
        Assert.AreEqual("B", second.EntityType);

        var third = sut.ReceiveNotification();
        Assert.IsNotNull(third);
        Assert.AreEqual("C", third.EntityType);

        // Queue should be empty now
        Assert.IsNull(sut.ReceiveNotification());
    }

    [TestMethod]
    public void MarkAsRead_DoesNotThrow()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act & Assert — no-op for in-memory implementation, but should not throw
        sut.MarkAsRead(42);
    }

    [TestMethod]
    public void Dispose_DoesNotThrow()
    {
        // Arrange
        var sut = new NotificationService();

        // Act & Assert
        sut.Dispose();
    }

    [TestMethod]
    public void SendNotification_SetsCreatedAtToRecentTime()
    {
        // Arrange
        using var sut = new NotificationService();
        var before = DateTime.Now.AddSeconds(-1);

        // Act
        sut.SendNotification("Test", "1", EntityOperation.CREATE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.CreatedAt >= before, "CreatedAt should be recent");
        Assert.IsTrue(notification.CreatedAt <= DateTime.Now.AddSeconds(1), "CreatedAt should not be in the future");
    }

    [TestMethod]
    public void SendNotification_TwoArgOverload_DelegatesToFiveArgOverload()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Instructor", "5", EntityOperation.DELETE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.AreEqual("Instructor", notification.EntityType);
        Assert.AreEqual("5", notification.EntityId);
        Assert.AreEqual("DELETE", notification.Operation);
        Assert.IsTrue(notification.Message.Contains("Instructor (ID: 5)"));
    }

    [TestMethod]
    public void SendNotification_WithNullDisplayName_UsesIdFallback()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Student", "99", null, EntityOperation.CREATE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Student (ID: 99)"));
    }

    [TestMethod]
    public void SendNotification_WithEmptyDisplayName_UsesIdFallback()
    {
        // Arrange
        using var sut = new NotificationService();

        // Act
        sut.SendNotification("Student", "99", "  ", EntityOperation.CREATE);

        // Assert
        var notification = sut.ReceiveNotification();
        Assert.IsNotNull(notification);
        Assert.IsTrue(notification.Message.Contains("Student (ID: 99)"));
    }
}

