using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class DbInitializerTests
{
    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsStudents()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsInstructors()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(5, context.Instructors.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsDepartments()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(4, context.Departments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourses()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(7, context.Courses.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsEnrollments()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(11, context.Enrollments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsOfficeAssignments()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(3, context.OfficeAssignments.Count());
    }

    [TestMethod]
    public void Initialize_EmptyDatabase_SeedsCourseAssignments()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(8, context.CourseAssignments.Count());
    }

    [TestMethod]
    public void Initialize_DatabaseAlreadySeeded_DoesNotDuplicate()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        DbInitializer.Initialize(context);
        var studentCountAfterFirst = context.Students.Count();

        // Act — initialize again
        DbInitializer.Initialize(context);

        // Assert
        Assert.AreEqual(studentCountAfterFirst, context.Students.Count());
    }

    [TestMethod]
    public void Initialize_SeedsCorrectStudentNames()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var studentNames = context.Students.Select(s => s.LastName).OrderBy(n => n).ToList();
        CollectionAssert.Contains(studentNames, "Alexander");
        CollectionAssert.Contains(studentNames, "Alonso");
        CollectionAssert.Contains(studentNames, "Norman");
        CollectionAssert.Contains(studentNames, "Olivetto");
    }

    [TestMethod]
    public void Initialize_SeedsDepartmentsWithCorrectBudgets()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var english = context.Departments.Single(d => d.Name == "English");
        Assert.AreEqual(350000m, english.Budget);

        var math = context.Departments.Single(d => d.Name == "Mathematics");
        Assert.AreEqual(100000m, math.Budget);
    }

    [TestMethod]
    public void Initialize_SeedsCoursesWithCorrectCredits()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var chemistry = context.Courses.Single(c => c.Title == "Chemistry");
        Assert.AreEqual(3, chemistry.Credits);
        Assert.AreEqual(1050, chemistry.CourseID);

        var calculus = context.Courses.Single(c => c.Title == "Calculus");
        Assert.AreEqual(4, calculus.Credits);
        Assert.AreEqual(1045, calculus.CourseID);
    }

    [TestMethod]
    public void Initialize_SeedsEnrollmentsWithGrades()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert — some enrollments should have grades, some shouldn't
        var gradedEnrollments = context.Enrollments.Where(e => e.Grade != null).Count();
        var ungradedEnrollments = context.Enrollments.Where(e => e.Grade == null).Count();
        Assert.IsTrue(gradedEnrollments > 0, "Should have graded enrollments");
        Assert.IsTrue(ungradedEnrollments > 0, "Should have ungraded enrollments");
    }

    [TestMethod]
    public void Initialize_DepartmentsHaveAdministrators()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Act
        DbInitializer.Initialize(context);

        // Assert
        var departments = context.Departments.ToList();
        Assert.IsTrue(departments.All(d => d.InstructorID != null),
            "All departments should have an administrator");
    }
}

