using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class StudentsControllerTests
{
    private static SchoolContext CreateSeededContext()
    {
        var context = TestDbContextFactory.Create();
        DbInitializer.Initialize(context);
        return context;
    }

    #region Index

    [TestMethod]
    public void Index_NoParameters_ReturnsViewWithPaginatedStudents()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index(null, null, null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.IsTrue(model.Count > 0);
    }

    [TestMethod]
    public void Index_DefaultSort_OrdersByLastNameAscending()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index(null, null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 1; i < model.Count; i++)
        {
            Assert.IsTrue(
                string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) <= 0,
                $"Expected {model[i - 1].LastName} <= {model[i].LastName}");
        }
    }

    [TestMethod]
    public void Index_NameDescSort_OrdersByLastNameDescending()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index("name_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 1; i < model.Count; i++)
        {
            Assert.IsTrue(
                string.Compare(model[i - 1].LastName, model[i].LastName, StringComparison.Ordinal) >= 0,
                $"Expected {model[i - 1].LastName} >= {model[i].LastName}");
        }
    }

    [TestMethod]
    public void Index_DateSort_OrdersByEnrollmentDateAscending()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index("Date", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 1; i < model.Count; i++)
        {
            Assert.IsTrue(model[i - 1].EnrollmentDate <= model[i].EnrollmentDate,
                $"Expected {model[i - 1].EnrollmentDate} <= {model[i].EnrollmentDate}");
        }
    }

    [TestMethod]
    public void Index_DateDescSort_OrdersByEnrollmentDateDescending()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index("date_desc", null, null, null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        for (int i = 1; i < model.Count; i++)
        {
            Assert.IsTrue(model[i - 1].EnrollmentDate >= model[i].EnrollmentDate);
        }
    }

    [TestMethod]
    public void Index_WithSearchString_FiltersResults()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act — search for "Alexander"
        var result = sut.Index(null, null, "Alexander", null) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
        Assert.AreEqual("Alexander", model[0].LastName);
    }

    [TestMethod]
    public void Index_WithSearchString_ResetsPageToOne()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Index(null, null, "Al", 5) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.PageIndex); // new search resets to page 1
    }

    [TestMethod]
    public void Index_WithCurrentFilter_MaintainsFilter()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act — currentFilter passed, no new searchString
        var result = sut.Index(null, "Alexander", null, 1) as ViewResult;

        // Assert
        var model = result!.Model as PaginatedList<Student>;
        Assert.IsNotNull(model);
        Assert.AreEqual(1, model.Count);
    }

    [TestMethod]
    public void Index_SetsViewBagSortParameters()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        sut.Index(null, null, null, null);

        // Assert
        Assert.AreEqual("name_desc", sut.ViewBag.NameSortParm);
        Assert.AreEqual("Date", sut.ViewBag.DateSortParm);
    }

    [TestMethod]
    public void Index_WithDateSort_SetsCorrectDateSortParm()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        sut.Index("Date", null, null, null);

        // Assert
        Assert.AreEqual("date_desc", sut.ViewBag.DateSortParm);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateSeededContext();
        var student = context.Students.First();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Details(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithDefaultDate()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(DateTime.Today, model.EnrollmentDate);
    }

    [TestMethod]
    public void Create_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = new DateTime(2024, 9, 1)
        };

        // Act
        var result = sut.Create(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(1, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);
        sut.ModelState.AddModelError("LastName", "Required");
        var student = new Student
        {
            FirstMidName = "Test",
            EnrollmentDate = new DateTime(2024, 9, 1)
        };

        // Act
        var result = sut.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(0, context.Students.Count());
    }

    [TestMethod]
    public void Create_Post_MinDateEnrollment_AddsModelError()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);
        var student = new Student
        {
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = sut.Create(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Edit((int?)null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Edit(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateSeededContext();
        var student = context.Students.First();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Edit(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void Edit_Post_ValidStudent_RedirectsToIndex()
    {
        // Arrange
        using var context = CreateSeededContext();
        var student = context.Students.First();
        student.LastName = "Updated";
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Edit(student) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
    }

    [TestMethod]
    public void Edit_Post_MinDateEnrollment_AddsModelError()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);
        var student = new Student
        {
            ID = 1,
            FirstMidName = "Test",
            LastName = "Student",
            EnrollmentDate = DateTime.MinValue
        };

        // Act
        var result = sut.Edit(student) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.IsTrue(sut.ModelState.ContainsKey("EnrollmentDate"));
    }

    #endregion

    #region Delete

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Delete(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithStudent()
    {
        // Arrange
        using var context = CreateSeededContext();
        var student = context.Students.First();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.Delete(student.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Student;
        Assert.IsNotNull(model);
        Assert.AreEqual(student.ID, model.ID);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesStudentAndRedirects()
    {
        // Arrange
        using var context = CreateSeededContext();
        var student = context.Students.First();
        var studentId = student.ID;
        var initialCount = context.Students.Count();
        using var sut = new StudentsController(context);

        // Act
        var result = sut.DeleteConfirmed(studentId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, context.Students.Count());
    }

    #endregion
}

