using ContosoUniversity.Controllers;
using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.AspNetCore.Mvc;

namespace ContosoUniversity.Tests.Controllers;

[TestClass]
public sealed class InstructorsControllerTests
{
    private static SchoolContext CreateSeededContext()
    {
        var context = TestDbContextFactory.Create();
        DbInitializer.Initialize(context);
        return context;
    }

    #region Index

    [TestMethod]
    public void Index_NoSelection_ReturnsViewWithAllInstructors()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Index(null, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.AreEqual(5, model.Instructors.Count());
    }

    [TestMethod]
    public void Index_WithInstructorSelected_PopulatesCourses()
    {
        // Arrange
        using var context = CreateSeededContext();
        var instructor = context.Instructors.First();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Index(instructor.ID, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Models.SchoolViewModels.InstructorIndexData;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.Courses);
        Assert.AreEqual(instructor.ID, (int)sut.ViewBag.InstructorID);
    }

    #endregion

    #region Details

    [TestMethod]
    public void Details_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Details(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Details_InvalidId_ReturnsNotFound()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Details(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Details_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        using var context = CreateSeededContext();
        var instructor = context.Instructors.First();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Details(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    #endregion

    #region Create

    [TestMethod]
    public void Create_Get_ReturnsViewWithInstructor()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Create() as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.IsNotNull(model.CourseAssignments);
    }

    [TestMethod]
    public void Create_Post_ValidInstructor_RedirectsToIndex()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);
        var instructor = new Instructor
        {
            FirstMidName = "NewFirst",
            LastName = "NewLast",
            HireDate = new DateTime(2024, 1, 1)
        };

        // Act
        var result = sut.Create(instructor, null) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.IsTrue(context.Instructors.Any(i => i.LastName == "NewLast"));
    }

    [TestMethod]
    public void Create_Post_WithSelectedCourses_AddsCourseAssignments()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);
        var courses = context.Courses.Take(2).ToList();
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "WithCourses",
            HireDate = new DateTime(2024, 1, 1)
        };
        var selectedCourses = courses.Select(c => c.CourseID.ToString()).ToArray();

        // Act
        var result = sut.Create(instructor, selectedCourses) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(2, instructor.CourseAssignments.Count);
    }

    [TestMethod]
    public void Create_Post_InvalidModelState_ReturnsView()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);
        sut.ModelState.AddModelError("LastName", "Required");
        var instructor = new Instructor
        {
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        var result = sut.Create(instructor, null) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
    }

    #endregion

    #region Edit

    [TestMethod]
    public void Edit_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Edit((int?)null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Edit_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        using var context = CreateSeededContext();
        var instructor = context.Instructors.First();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Edit(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    #endregion

    #region Delete

    [TestMethod]
    public void Delete_Get_NullId_ReturnsBadRequest()
    {
        // Arrange
        using var context = CreateSeededContext();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Delete(null) as StatusCodeResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual(400, result.StatusCode);
    }

    [TestMethod]
    public void Delete_Get_InvalidId_ReturnsNotFound()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Delete(99999) as NotFoundResult;

        // Assert
        Assert.IsNotNull(result);
    }

    [TestMethod]
    public void Delete_Get_ValidId_ReturnsViewWithInstructor()
    {
        // Arrange
        using var context = CreateSeededContext();
        var instructor = context.Instructors.First();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.Delete(instructor.ID) as ViewResult;

        // Assert
        Assert.IsNotNull(result);
        var model = result.Model as Instructor;
        Assert.IsNotNull(model);
        Assert.AreEqual(instructor.ID, model.ID);
    }

    [TestMethod]
    public void DeleteConfirmed_ValidId_RemovesInstructorAndRedirects()
    {
        // Arrange
        using var context = CreateSeededContext();
        // Choose an instructor that is NOT a department administrator to avoid FK issues
        var instructorNames = context.Departments.Select(d => d.InstructorID).ToList();
        var instructor = context.Instructors.First(i => !instructorNames.Contains(i.ID));
        var instructorId = instructor.ID;
        var initialCount = context.Instructors.Count();
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.DeleteConfirmed(instructorId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        Assert.AreEqual("Index", result.ActionName);
        Assert.AreEqual(initialCount - 1, context.Instructors.Count());
    }

    [TestMethod]
    public void DeleteConfirmed_DepartmentAdmin_NullsOutDepartmentInstructorID()
    {
        // Arrange
        using var context = CreateSeededContext();
        var dept = context.Departments.First(d => d.InstructorID != null);
        var instructorId = dept.InstructorID!.Value;
        using var sut = new InstructorsController(context);

        // Act
        var result = sut.DeleteConfirmed(instructorId) as RedirectToActionResult;

        // Assert
        Assert.IsNotNull(result);
        // Re-query the department
        var updatedDept = context.Departments.Find(dept.DepartmentID);
        Assert.IsNull(updatedDept!.InstructorID);
    }

    #endregion
}

