using ContosoUniversity.Data;
using ContosoUniversity.Models;
using ContosoUniversity.Tests.Helpers;
using Microsoft.EntityFrameworkCore;

namespace ContosoUniversity.Tests.Data;

[TestClass]
public sealed class SchoolContextTests
{
    [TestMethod]
    public void SchoolContext_HasAllExpectedDbSets()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();

        // Assert — verify all DbSet properties are accessible
        Assert.IsNotNull(context.Courses);
        Assert.IsNotNull(context.Enrollments);
        Assert.IsNotNull(context.Departments);
        Assert.IsNotNull(context.OfficeAssignments);
        Assert.IsNotNull(context.CourseAssignments);
        Assert.IsNotNull(context.People);
        Assert.IsNotNull(context.Students);
        Assert.IsNotNull(context.Instructors);
        Assert.IsNotNull(context.Notifications);
    }

    [TestMethod]
    public void SchoolContext_CourseAssignment_HasCompositeKey()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Instructor",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        var course = new Course
        {
            CourseID = 5001,
            Title = "Test Course",
            Credits = 3,
            DepartmentID = 0
        };
        context.Courses.Add(course);
        context.SaveChanges();

        // Act — add course assignment with composite key
        var assignment = new CourseAssignment
        {
            CourseID = course.CourseID,
            InstructorID = instructor.ID
        };
        context.CourseAssignments.Add(assignment);
        context.SaveChanges();

        // Assert
        var found = context.CourseAssignments.Find(course.CourseID, instructor.ID);
        Assert.IsNotNull(found);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveStudent()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            FirstMidName = "Jane",
            LastName = "Doe",
            EnrollmentDate = new DateTime(2024, 9, 1)
        };

        // Act
        context.Students.Add(student);
        context.SaveChanges();

        // Assert
        var found = context.Students.Single(s => s.LastName == "Doe");
        Assert.AreEqual("Jane", found.FirstMidName);
        Assert.AreEqual(new DateTime(2024, 9, 1), found.EnrollmentDate);
    }

    [TestMethod]
    public void SchoolContext_CanAddAndRetrieveNotification()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var notification = new Notification
        {
            EntityType = "Test",
            EntityId = "1",
            Operation = "CREATE",
            Message = "Test message",
            CreatedAt = DateTime.Now,
            CreatedBy = "System",
            IsRead = false
        };

        // Act
        context.Notifications.Add(notification);
        context.SaveChanges();

        // Assert
        var found = context.Notifications.Single();
        Assert.AreEqual("Test", found.EntityType);
        Assert.AreEqual("Test message", found.Message);
    }

    [TestMethod]
    public void SchoolContext_TPH_StudentAndInstructorSharePersonTable()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var student = new Student
        {
            FirstMidName = "Bob",
            LastName = "Student",
            EnrollmentDate = DateTime.Today
        };
        var instructor = new Instructor
        {
            FirstMidName = "Alice",
            LastName = "Instructor",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };

        // Act
        context.Students.Add(student);
        context.Instructors.Add(instructor);
        context.SaveChanges();

        // Assert — both are in People table
        var people = context.People.ToList();
        Assert.AreEqual(2, people.Count);
        Assert.IsTrue(people.Any(p => p is Student));
        Assert.IsTrue(people.Any(p => p is Instructor));
    }

    [TestMethod]
    public void SchoolContext_OfficeAssignment_OneToOneWithInstructor()
    {
        // Arrange
        using var context = TestDbContextFactory.Create();
        var instructor = new Instructor
        {
            FirstMidName = "Test",
            LastName = "Prof",
            HireDate = DateTime.Today,
            CourseAssignments = new List<CourseAssignment>()
        };
        context.Instructors.Add(instructor);
        context.SaveChanges();

        // Act
        var office = new OfficeAssignment
        {
            InstructorID = instructor.ID,
            Location = "Room 101"
        };
        context.OfficeAssignments.Add(office);
        context.SaveChanges();

        // Assert
        var found = context.OfficeAssignments.Find(instructor.ID);
        Assert.IsNotNull(found);
        Assert.AreEqual("Room 101", found.Location);
    }
}

